// ── GLOBAL STYLES ─────────────────────────────────────────────────────────────
(() => {
  // ── viewport-fit=cover: unlocks env(safe-area-inset-*) for iPhone notch / Dynamic Island
  let vp = document.querySelector('meta[name="viewport"]');
  if (!vp) { vp = document.createElement('meta'); vp.name = 'viewport'; document.head.appendChild(vp); }
  if (!vp.content.includes('viewport-fit')) vp.content = (vp.content || 'width=device-width, initial-scale=1') + ', viewport-fit=cover';

  // ── PWA meta tags — enables "Add to Home Screen" as a native-feeling app on iOS/Android
  const pwaMeta = [
    { name:'apple-mobile-web-app-capable',           content:'yes' },
    { name:'apple-mobile-web-app-status-bar-style',  content:'black-translucent' },
    { name:'apple-mobile-web-app-title',             content:'LifeOS' },
    { name:'mobile-web-app-capable',                 content:'yes' },
    { name:'application-name',                       content:'LifeOS' },
  ];
  pwaMeta.forEach(({ name, content }) => {
    if (!document.querySelector(`meta[name="${name}"]`)) {
      const m = document.createElement('meta'); m.name = name; m.content = content;
      document.head.appendChild(m);
    }
  });
  // theme-color — colors browser chrome / status bar on Android Chrome
  if (!document.querySelector('meta[name="theme-color"]')) {
    const tc = document.createElement('meta'); tc.name = 'theme-color'; tc.content = '#040408';
    document.head.appendChild(tc);
  }
  // apple touch icon — used when pinned to home screen on iOS
  if (!document.querySelector('link[rel="apple-touch-icon"]')) {
    const icon = document.createElement('link'); icon.rel = 'apple-touch-icon';
    const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 180 180"><rect width="180" height="180" rx="40" fill="%23040408"/><rect x="30" y="50" width="4" height="80" rx="2" fill="%2300f5d4" opacity=".6"/><text x="44" y="115" font-family="system-ui,sans-serif" font-weight="800" font-size="64" fill="%2300f5d4">OS</text></svg>`;
    icon.href = `data:image/svg+xml,${svg}`;
    document.head.appendChild(icon);
  }
  // manifest.json — links the installed PWA manifest (file already in /lifeos/ repo)
  if (!document.querySelector('link[rel="manifest"]')) {
    const mf = document.createElement('link'); mf.rel = 'manifest'; mf.href = '/lifeos/manifest.json';
    document.head.appendChild(mf);
  }
  // Service Worker — register sw.js already in /lifeos/ repo
  if ('serviceWorker' in navigator) {
    window.addEventListener('load', () => {
      navigator.serviceWorker.register('/lifeos/sw.js', { scope: '/lifeos/' })
        .then(reg => console.log('[LifeOS SW] registered, scope:', reg.scope))
        .catch(err => console.warn('[LifeOS SW] registration failed:', err));
    });
  }

  const link = document.createElement('link');
  link.rel = 'stylesheet';
  link.href = 'https://fonts.googleapis.com/css2?family=Cabinet+Grotesk:wght@400;500;700;800&family=DM+Mono:ital,wght@0,400;0,500;1,400&family=Nunito:wght@400;500;600;700;800&display=swap';
  document.head.appendChild(link);
  const style = document.createElement('style');
  style.textContent = `
    * { box-sizing: border-box; margin: 0; padding: 0; }
    html, body { height: 100%; overflow: hidden; overscroll-behavior: none; -webkit-text-size-adjust: 100%; }
    :root {
      --sat: env(safe-area-inset-top, 0px);
      --sab: env(safe-area-inset-bottom, 0px);
      --sal: env(safe-area-inset-left, 0px);
      --sar: env(safe-area-inset-right, 0px);
    }
    ::-webkit-scrollbar { width: 2px; height: 2px; }
    ::-webkit-scrollbar-track { background: transparent; }
    ::-webkit-scrollbar-thumb { background: rgba(0,245,212,0.18); border-radius: 2px; }
    @keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
    @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
    @keyframes glowPulse { 0%,100% { box-shadow:0 0 8px rgba(0,245,212,0.25); } 50% { box-shadow:0 0 28px rgba(0,245,212,0.65),0 0 50px rgba(0,245,212,0.12); } }
    @keyframes dotPulse { 0%,100% { transform:scale(1); opacity:1; } 50% { transform:scale(1.6); opacity:0.5; } }
    @keyframes nodeEnter { from { opacity:0; transform:scale(0.8) translateX(-8px); } to { opacity:1; transform:scale(1) translateX(0); } }
    @keyframes modalIn { from { opacity:0; transform:scale(0.92); } to { opacity:1; transform:scale(1); } }
    @keyframes countUp { from { opacity:0; transform:translateY(6px); } to { opacity:1; transform:translateY(0); } }
    @keyframes slideDown { from { opacity:0; transform:translateY(-8px); } to { opacity:1; transform:translateY(0); } }
    @keyframes toastTimer { from { width:100%; } to { width:0%; } }
    @keyframes xpPop { 0% { opacity:0; transform:translateY(16px) scale(0.85); } 15% { opacity:1; transform:translateY(-4px) scale(1.06); } 30% { transform:translateY(0) scale(1); } 70% { opacity:1; transform:translateY(0) scale(1); } 100% { opacity:0; transform:translateY(-20px) scale(0.92); } }
    @keyframes fabItemIn { from { opacity:0; transform:scale(0.4); } to { opacity:1; transform:scale(1); } }
    @keyframes badgeIn { from { opacity:0; transform:scale(0.7) rotateY(90deg); } to { opacity:1; transform:scale(1) rotateY(0deg); } }
    @keyframes spin { from { transform:rotate(0deg); } to { transform:rotate(360deg); } }
    @keyframes float { 0%,100% { transform:translateY(0px) scale(1); opacity:0.7; } 50% { transform:translateY(-18px) scale(1.08); opacity:1; } }
    @keyframes floatSlow { 0%,100% { transform:translateY(0px) translateX(0px); } 33% { transform:translateY(-12px) translateX(8px); } 66% { transform:translateY(6px) translateX(-6px); } }
    @keyframes pulseGlow { 0%,100% { opacity:0.4; transform:scale(1); } 50% { opacity:0.9; transform:scale(1.15); } }
    @keyframes ambientDrift { 0% { transform:translate(0,0) scale(1); } 25% { transform:translate(60px,-40px) scale(1.12); } 50% { transform:translate(20px,60px) scale(0.95); } 75% { transform:translate(-50px,10px) scale(1.06); } 100% { transform:translate(0,0) scale(1); } }
    @keyframes graphEdge { from { stroke-dashoffset:200; opacity:0; } to { stroke-dashoffset:0; opacity:1; } }
    @keyframes nodeFloat { 0%,100% { transform:translate(0,0); } 50% { transform:translate(0,-4px); } }
    @media (max-width:767px) {
      .los-desktop-only { display:none !important; }
      .los-mobile-only { display:flex !important; }
    }
    @media (min-width:768px) {
      .los-mobile-only { display:none !important; }
      .los-input { font-size: 12px !important; }
    }
    @keyframes slideUp { from { transform:translateY(100%); opacity:0.6; } to { transform:translateY(0); opacity:1; } }
    /* iOS tap highlight — removes grey flash on every tap */
    * { -webkit-tap-highlight-color: transparent; }
    /* Disable hover effects on touch devices — prevents sticky hover after tap */
    @media (hover:none) {
      .los-btn:hover { filter:none !important; transform:none !important; }
      .los-card:hover { border-color:rgba(255,255,255,0.07) !important; }
      .los-nav:hover { background:transparent !important; }
      .los-qa:hover  { background:transparent !important; transform:none !important; }
      .los-tab:hover { background:transparent !important; }
      .los-row:hover { background:transparent !important; }
    }
    /* Shared textarea style — avoids 50+ repeated inline blocks + ensures 16px on mobile */
    .los-textarea {
      width:100%; padding:9px 12px;
      background:var(--los-input-bg, rgba(255,255,255,0.04));
      border:1px solid var(--los-border, rgba(255,255,255,0.07));
      border-radius:10px; font-family:inherit;
      font-size:13px; color:var(--los-text, #dde0f2); resize:vertical;
      transition:border-color 0.2s; line-height:1.5;
    }
    .los-textarea:focus { border-color:var(--los-accent-focus, rgba(0,245,212,0.5)); }
    [data-theme="light"] {
      --los-input-bg:    rgba(0,0,0,0.04);
      --los-border:      rgba(0,0,0,0.10);
      --los-text:        #1e1e2e;
      --los-accent-focus:rgba(0,168,150,0.6);
    }
    /* Touch-friendly × close buttons */
    .los-close-btn { min-width:44px; min-height:44px; display:inline-flex; align-items:center; justify-content:center; border-radius:8px; cursor:pointer; transition:background 0.15s; }
    .los-close-btn:hover { background:rgba(255,255,255,0.08); }
    /* Modal scroll lock — overflow:hidden blocks background scroll;
       touch-action:none removed here because it propagates to children and
       kills inner scroll on Android WebViews */
    body.los-modal-open { overflow:hidden; }
    /* Bottom sheet inner scroll — touch-action:pan-y re-enables vertical
       swipe gestures inside the sheet on Android despite body overflow:hidden */
    .los-sheet-body { overflow-y: auto; -webkit-overflow-scrolling: touch; overscroll-behavior: contain; touch-action: pan-y; max-height: calc(92vh - 120px); flex: 1; min-height: 0; }
    /* TabNav: horizontal scroll on mobile, no wrapping */
    .los-tabnav { overflow-x:auto; -ms-overflow-style:none; scrollbar-width:none; }
    .los-tabnav::-webkit-scrollbar { display:none; }
    /* PageHeader: responsive title size */
    @media (max-width:767px) {
      .los-page-title { font-size:20px !important; }
      .los-page-domain { font-size:7px !important; }
      /* iOS input zoom fix — Safari zooms in on inputs with font-size < 16px */
      input, textarea, select, .los-textarea { font-size: 16px !important; }
      .los-input { font-size: 16px !important; }
      /* Touch targets — minimum 44px (Apple HIG) for tappable elements */
      .los-btn { min-height: 44px !important; padding: 8px 16px !important; }
      .los-tab { min-height: 44px !important; padding: 8px 13px !important; }
      /* Responsive grids — prevent overflow on 390px screens */
      [style*="minmax(280px"] { grid-template-columns: 1fr !important; }
      [style*="minmax(200px"] { grid-template-columns: repeat(2,1fr) !important; }
      [style*="minmax(170px"] { grid-template-columns: repeat(2,1fr) !important; }
      [style*="minmax(160px"] { grid-template-columns: repeat(2,1fr) !important; }
      [style*="minmax(150px"] { grid-template-columns: repeat(2,1fr) !important; }
    }
    /* Bottom nav tap feedback */
    .los-bottom-nav button:active { transform: scale(0.88); opacity: 0.75; transition: transform 0.08s, opacity 0.08s; }
    .los-btn:hover { filter:brightness(1.2); transform:translateY(-1px); }
    .los-card:hover { border-color:rgba(0,245,212,0.18) !important; }
    .los-nav:hover { background:rgba(0,245,212,0.08) !important; }
    .los-qa:hover { background:rgba(255,255,255,0.07) !important; transform:translateY(-2px); }
    .los-ev:hover { background:rgba(255,255,255,0.04) !important; }
    .los-tab:hover { background:rgba(255,255,255,0.05) !important; }
    .los-row:hover { background:rgba(255,255,255,0.03) !important; }
    .los-cmd:hover { background:rgba(255,255,255,0.06) !important; }
    .los-heat:hover { transform:scale(1.4); z-index:10; }
    /* UX fix: keep outline:none for mouse users but restore visible focus ring for
       keyboard/AT users via :focus-visible. Previously ALL focus indicators were
       removed, making keyboard navigation effectively invisible. */
    input, textarea, select { outline:none; font-family:inherit; }
    input:focus, textarea:focus, select:focus { border-color:rgba(0,245,212,0.5) !important; }
    button { cursor:pointer; border:none; background:none; font-family:inherit; transition:all 0.18s ease; }
    button:focus-visible { outline: 2px solid rgba(0,245,212,0.7); outline-offset: 2px; border-radius: 6px; }
    a:focus-visible { outline: 2px solid rgba(0,245,212,0.7); outline-offset: 2px; border-radius: 4px; }
    select option { background:#0b0b1a; color:#dde0f2; }
    /* Battery / accessibility: suppress looping ambient animations for users
       who prefer reduced motion or on any device that opts in */
    @media (prefers-reduced-motion: reduce) {
      *[style*="glowPulse"], *[style*="dotPulse"] { animation: none !important; }
    }
    /* Page skeleton — shimmer bars shown while async content loads */
    @keyframes shimmer { from { background-position: -400px 0; } to { background-position: 400px 0; } }
    .los-skeleton {
      border-radius: 6px;
      background: linear-gradient(90deg, rgba(255,255,255,0.04) 25%, rgba(255,255,255,0.09) 50%, rgba(255,255,255,0.04) 75%);
      background-size: 800px 100%;
      animation: shimmer 1.4s infinite linear;
    }
    /* Page fade-in — replaces blank flash on navigation */
    .los-page-enter { animation: fadeIn 0.18s ease both; }
  `;
  document.head.appendChild(style);
})();

