// ── AI ROUTER ─────────────────────────────────────────────────────────────────
// Single entry point for all AI calls. Routes to Ollama, OpenAI, Anthropic,
// or GitHub Models based on settings.aiProvider. Add new providers here — nowhere else.
async function callAI(settings, { system, messages, max_tokens = 1000 }) {
  const provider = settings?.aiProvider || 'claude';

  // ── OLLAMA (local) ──────────────────────────────────────────────────────────
  if (provider === 'ollama') {
    const model = settings?.ollamaModel || 'llama3.2';
    const ollamaHost = settings?.ollamaHost?.trim() || 'localhost';
    const res = await fetch(`http://${ollamaHost}:11434/api/chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model,
        stream: false,
        messages: [
          ...(system ? [{ role: 'system', content: system }] : []),
          ...messages,
        ],
      }),
    });
    if (!res.ok) {
      const err = await res.text().catch(() => res.statusText);
      throw new Error(`Ollama error (${res.status}): ${err}`);
    }
    const data = await res.json();
    return data.message?.content || '';
  }

  // ── OPENAI ──────────────────────────────────────────────────────────────────
  if (provider === 'openai') {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${settings?.aiApiKey || ''}`,
      },
      body: JSON.stringify({
        model: 'gpt-4o',
        max_tokens,
        messages: [
          ...(system ? [{ role: 'system', content: system }] : []),
          ...messages,
        ],
      }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err?.error?.message || `OpenAI error ${res.status}`);
    }
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '';
  }

  // ── GROQ (free tier) ────────────────────────────────────────────────────────
  // Free API key at console.groq.com — Llama 3.3 70B, very fast.
  if (provider === 'groq') {
    const res = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${settings?.aiApiKey || ''}`,
      },
      body: JSON.stringify({
        model: 'llama-3.3-70b-versatile',
        max_tokens,
        messages: [
          ...(system ? [{ role: 'system', content: system }] : []),
          ...messages,
        ],
      }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err?.error?.message || `Groq error ${res.status}`);
    }
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '';
  }

  // ── GITHUB MODELS (free) ────────────────────────────────────────────────────
  // Uses your existing GitHub PAT — free tier, OpenAI-compatible endpoint.
  // Model: gpt-4o-mini (most generous free quota). Vision also supported.
  if (provider === 'github') {
    const model = settings?.githubModel || 'gpt-4o-mini';
    const res = await fetch('https://models.inference.ai.azure.com/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${settings?.aiApiKey || ''}`,
      },
      body: JSON.stringify({
        model,
        max_tokens,
        messages: [
          ...(system ? [{ role: 'system', content: system }] : []),
          ...messages,
        ],
      }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err?.error?.message || `GitHub Models error ${res.status}`);
    }
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '';
  }

  // ── ANTHROPIC (default) ─────────────────────────────────────────────────────
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': settings?.aiApiKey || '',
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens,
      system,
      messages,
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err?.error?.message || `Anthropic error ${res.status}`);
  }
  const data = await res.json();
  return data.content?.[0]?.text || '';
}

// ── VISION VARIANT — wraps callAI for image+text messages ────────────────────
// Builds the provider-specific image block format so ReceiptScannerModal
// (and any future vision feature) never touches raw fetch() directly.
async function callAIVision(settings, { b64, mimeType, prompt, max_tokens = 400 }) {
  const provider = settings?.aiProvider || 'claude';
  if (provider === 'ollama') {
    throw new Error('Receipt Scanner requires a vision model. Switch to Anthropic, OpenAI, or GitHub Models in Settings → AI Provider.');
  }
  if (provider === 'openai' || provider === 'github') {
    // GPT-4o / gpt-4o-mini expect image_url with a data URI (same format for both)
    return callAI(settings, {
      max_tokens,
      messages: [{
        role: 'user',
        content: [
          { type: 'image_url', image_url: { url: `data:${mimeType};base64,${b64}` } },
          { type: 'text', text: prompt },
        ],
      }],
    });
  }
  // Anthropic — image block with base64 source
  return callAI(settings, {
    max_tokens,
    messages: [{
      role: 'user',
      content: [
        { type: 'image', source: { type: 'base64', media_type: mimeType, data: b64 } },
        { type: 'text', text: prompt },
      ],
    }],
  });
}

// ── LIFE CONTEXT BUILDER — single source of truth for all AI system prompts ──
// Accepts the full `data` object (same shape as the root data prop) and returns
// a formatted context string. All AI features (Intelligence coach, Knowledge
// chat, FinCoach, Weekly Brief, etc.) call this instead of building their own.
function buildLifeContext(data) {
  const {
    expenses=[], incomes=[], habits=[], habitLogs={}, vitals=[], goals=[],
    assets=[], investments=[], debts=[], totalXP=0, settings={}, computed={},
  } = data || {};
  const cur = settings?.currency || '$';
  const m = today().slice(0,7);
  const mInc  = computed?.monthInc  ?? (incomes||[]).filter(i=>i.date?.startsWith(m)).reduce((s,i)=>s+Number(i.amount||0),0);
  const mExp  = computed?.monthExp  ?? (expenses||[]).filter(e=>e.date?.startsWith(m)).reduce((s,e)=>s+Number(e.amount||0),0);
  const invVal = computed?.invVal   ?? (investments||[]).reduce((s,i)=>s+Number((i.currentPrice??i.buyPrice)||0)*Number(i.quantity||0),0);
  const nw    = computed?.nw        ?? ((assets||[]).reduce((s,a)=>s+Number(a.value||0),0)+invVal-(debts||[]).reduce((s,d)=>s+Number(d.balance||0),0));
  const savRate = computed?.savRate ?? (mInc>0?((mInc-mExp)/mInc*100):0);
  const habitSum = (habits||[]).map(h=>`${h.name} (streak:${getStreak(h.id,habitLogs)}d)`).join(', ') || 'none';
  const goalSum  = (goals||[]).map(g=>`${g.name}: ${Math.round(((g.current||0)/Math.max(1,g.target))*100)}%`).join(', ') || 'none';
  const v7 = (vitals||[]).slice(-7);
  const avgSlp = v7.length ? (v7.reduce((s,v)=>s+Number(v.sleep||0),0)/v7.length).toFixed(1) : 'N/A';
  const topExp = [...(expenses||[])].sort((a,b)=>Number(b.amount||0)-Number(a.amount||0)).slice(0,5).map(e=>`${e.category}: ${cur}${e.amount}`).join(', ') || 'none';
  const level = Math.floor(Math.sqrt(Number(totalXP)/100))+1;
  return `USER'S REAL LIFE DATA (LifeOS):
Net Worth: ${cur}${fmtN(nw)} | Investments: ${cur}${fmtN(invVal)}
This Month: Income ${cur}${fmtN(mInc)}, Expenses ${cur}${fmtN(mExp)}, Savings rate ${savRate.toFixed(1)}%
Top expenses: ${topExp}
Debts: ${(debts||[]).length} totaling ${cur}${fmtN((debts||[]).reduce((s,d)=>s+Number(d.balance||0),0))}
Habits: ${habitSum}
Goals: ${goalSum}
Avg Sleep (7d): ${avgSlp}h
Level: ${level}, ${totalXP} XP`;
}

// ── S5: THEME BOOT — apply saved theme before first render ───────────────────
// Reads localStorage synchronously at module load so T is correct on the very
// first paint — no flash of wrong theme (FOWT) on refresh or cold start.
(() => {
  try {
    const raw = localStorage.getItem('los_settings');
    if (raw) {
      const saved = JSON.parse(raw);
      const theme = saved?.theme;
      if (theme && THEMES[theme]) { Object.assign(T, THEMES[theme]); document.documentElement.dataset.theme = theme; }
    }
  } catch {} // silent — fall back to dark
})();

